protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: default discriminator property renamed from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing 500K documents and direct SQL queries remain compatible.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Preserve the old "Product|123" format so existing documents are still found by key lookups.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // HasIndex removed — Cosmos DB throws at startup in EF Core 9.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

